import { jsx, jsxs } from 'react/jsx-runtime';
import { useState, useEffect } from 'react';
import { classNames } from '../../helpers/classnames.js';
import { Button } from '../Button/Button.js';
import '../Button/ProgressButton/ProgressButton.js';
import { standardColorPallet } from './constants.js';
import { isDarkColor } from './utils.js';

const ColorPicker = ({ color = null, clearable = false, onChange }) => {
    const colors = [...standardColorPallet];
    const [internalColor, setInternalColor] = useState(color);
    useEffect(() => {
        setInternalColor(color);
    }, [color]);
    const equalsColor = (color1, color2) => {
        if (!color1 || !color2) {
            return false;
        }
        return color1.toLowerCase() === color2.toLowerCase();
    };
    const handleColorChange = (selectedColor, event) => {
        // Предотвращаем всплытие события, чтобы не мешать работе dropdown
        event?.stopPropagation();
        const newColor = selectedColor ? selectedColor.hex : null;
        setInternalColor(newColor);
        onChange?.(newColor);
    };
    // Добавляем пользовательский цвет в палитру если его нет
    useEffect(() => {
        if (internalColor && !colors.find(findColor => equalsColor(findColor.hex, internalColor))) {
            colors.push({ hex: internalColor, title: 'Пользовательский' });
        }
    }, [internalColor, colors]);
    const renderColorGrid = () => (jsxs("div", { className: "dsb_color-picker__grid", children: [jsx("div", { className: "dsb_color-picker__grid-colors", children: colors.map(colorItem => (jsx(Button, { variant: "plain", size: "small", className: classNames('dsb_color-picker__color-block', {
                        'dsb_color-picker__color-block--selected': equalsColor(colorItem.hex, internalColor),
                    }), style: { backgroundColor: colorItem.hex }, onClick: event => handleColorChange(colorItem, event), title: `${colorItem.title}: ${colorItem.hex}`, children: equalsColor(colorItem.hex, internalColor) && (jsx("div", { className: "dsb_color-picker__color-block-indicator", style: { backgroundColor: isDarkColor(colorItem.hex) ? '#FFFFFF' : '#000000' } })) }, colorItem.hex))) }), clearable && internalColor && (jsx(Button, { variant: "plain", size: "small", fullWidth: true, onClick: event => handleColorChange(null, event), className: "dsb_color-picker__clear-button", children: "\u043E\u0447\u0438\u0441\u0442\u0438\u0442\u044C \u0432\u044B\u0431\u043E\u0440" }))] }));
    return (jsx("div", { className: "dsb_color-picker", "data-testid": "ColorPicker", children: renderColorGrid() }));
};

export { ColorPicker };
